class SocialLoginManager(private val context: Context) {
    private val facebookCallbackManager: CallbackManager = CallbackManager.Factory.create()
    private var googleSignInClient: GoogleSignInClient? = null

    init {
        setupGoogleSignIn()
        setupFacebookLogin()
    }

    private fun setupGoogleSignIn() {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestIdToken("1234-abcdef.apps.googleusercontent.com")
            .build()
        googleSignInClient = GoogleSignIn.getClient(context, gso)
    }

    private fun setupFacebookLogin() {
        LoginManager.getInstance().logInWithReadPermissions(
            context as AppCompatActivity,
            listOf("public_profile", "email")
        )
    }

    fun signInWithFacebook(): Unit {
        LoginManager.getInstance().registerCallback(
            facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    // Handle Facebook login success
                }

                override fun onCancel() {
                    // Handle Facebook login cancel
                }

                override fun onError(error: FacebookException) {
                    // Handle Facebook login error
                }
            }
        )
    }

    fun signInWithGoogle(requestCode: Int) {
        val signInIntent = googleSignInClient?.signInIntent
        (context as AppCompatActivity).startActivityForResult(signInIntent, requestCode)
    }

    fun handleFacebookResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        return facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    fun handleGoogleResult(requestCode: Int, resultCode: Int, data: Intent?): Task<GoogleSignInAccount>? {
        return try {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            task.getResult(ApiException::class.java)
            null
        } catch (e: ApiException) {
            null
        }
    }

    fun getFacebookAccessToken(): String? {
        return if (AccessToken.getCurrentAccessToken() != null) {
            AccessToken.getCurrentAccessToken().token
        } else {
            null
        }
    }

    fun signOut() {
        LoginManager.getInstance().logOut()
        googleSignInClient?.signOut()
    }
}

class MainActivity : AppCompatActivity() {
    private lateinit var socialLoginManager: SocialLoginManager
    private val RC_GOOGLE_SIGN_IN = 9001

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        socialLoginManager = SocialLoginManager(this)
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        
        if (requestCode == RC_GOOGLE_SIGN_IN) {
            socialLoginManager.handleGoogleResult(requestCode, resultCode, data)
        } else {
            socialLoginManager.handleFacebookResult(requestCode, resultCode, data)
        }
    }

    fun performFacebookLogin() {
        socialLoginManager.signInWithFacebook()
    }

    fun performGoogleLogin() {
        socialLoginManager.signInWithGoogle(RC_GOOGLE_SIGN_IN)
    }

    fun isUserLoggedIn(): Boolean {
        return socialLoginManager.getFacebookAccessToken() != null || 
               GoogleSignIn.getLastSignedInAccount(this) != null
    }
}